const Web3 = require('web3');
const web3 = new Web3(new Web3.providers.HttpProvider('http://localhost:8545'));

// Wallet configuration with private keys for signing transactions
const account = web3.eth.accounts.privateKeyToAccount("YOUR_PRIVATE_KEY");
web3.eth.accounts.wallet.add(account);

// Function to send ETH
async function sendEth() {
  const fromAddress = account.address;
  const toAddress = "RECIPIENT_ADDRESS";
  const value = web3.utils.toWei("1", "ether"); // 1 ETH

  const tx = await web3.eth.sendTransaction({
    from: fromAddress,
    to: toAddress,
    value: value,
    gasLimit: 21000,
    gasPrice: web3.utils.toWei("20", "gwei") // 20 GWEI
  });

  console.log(`Transaction hash: ${tx.hash}`);
}

// Function to interact with smart contracts
async function interactWithContract() {
  const fromAddress = account.address;
  const toAddress = "CONTRACT_ADDRESS";
  const abi = JSON.parse("YOUR_CONTRACT_ABI"); // Parse the ABI of your smart contract
  const contract = new web3.eth.Contract(abi, toAddress);

  const methodName = "methodName"; // The name of the method you want to call on the smart contract
  const params = [arg1, arg2]; // Any parameters you want to pass to the method

  const tx = await contract.methods[methodName](...params).send({
    from: fromAddress,
    gasLimit: 21000,
    gasPrice: web3.utils.toWei("20", "gwei") // 20 GWEI
  });

  console.log(`Transaction hash: ${tx.hash}`);
}